# tests/test_portfolio_agent.py
import pytest
from adk.testing import AgentTestHarness, mock_tool, deterministic_llm

from myagent.agent import PortfolioAgent, get_stock_price


@pytest.fixture
def harness():
    # deterministic_llm replaces the real LLM with a scripted response sequence.
    # mock_tool intercepts tool calls and returns the provided values.
    return AgentTestHarness(
        agent_class=PortfolioAgent,
        llm=deterministic_llm([
            # Turn 1: model decides to call get_stock_price
            {"type": "tool_call", "name": "get_stock_price", "args": {"ticker": "AAPL"}},
            # Turn 2: model generates the final answer after seeing tool result
            {"type": "text", "content": "AAPL is currently trading at $189.42."},
        ]),
        tools={
            get_stock_price: mock_tool(return_value={"ticker": "AAPL", "price": 189.42, "currency": "USD"})
        }
    )


def test_agent_calls_price_tool_and_formats_answer(harness):
    result = harness.run("What is the price of AAPL?")
    assert "189.42" in result.content
    assert harness.tool_calls["get_stock_price"] == [{"ticker": "AAPL"}]


def test_agent_does_not_invent_prices_without_tool_call(harness):
    # Verify the agent never skips the tool call — the harness fails if
    # the model emits a final answer before calling get_stock_price.
    result = harness.run("What is the price of AAPL?")
    assert len(harness.tool_calls["get_stock_price"]) >= 1
